#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        unsigned long long n; scanf("%llu", &n);
        int cnt = 0;
        while((n & 1ULL) == 0ULL){
            cnt++;
            n >>= 1;
        }
        printf("%d\n", (cnt % 2 == 0) ? 1 : 0);
    }
    return 0;
}

