#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    idx = 1
    for _ in range(t):
        n = int(data[idx]); idx += 1
        cnt = 0
        while n & 1 == 0:
            cnt += 1
            n >>= 1
        out.append('1' if cnt % 2 == 0 else '0')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

